import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

function ViewAnswers() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [question, setQuestion] = useState(null);
  const [answer, setAnswer] = useState("");

  const user = JSON.parse(localStorage.getItem("user"));

  // 🔍 DEBUG (you can remove later)
  console.log("USER:", user);

  // ✅ Fetch question
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => {
        const found = data.find((q) => q._id === id);
        setQuestion(found);
      })
      .catch((err) => console.error(err));
  }, [id]);

  // ✅ Submit answer
  const handleAnswer = async () => {
    if (!answer) {
      alert("Enter answer");
      return;
    }

    try {
      const res = await fetch(`http://localhost:5000/api/answer/${id}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          answer: answer,
          answeredBy: user.name,
        }),
      });

      const data = await res.json();

      setQuestion(data); // update UI instantly
      setAnswer("");

      alert("Answer submitted!");
    } catch (err) {
      console.error(err);
      alert("Error submitting answer");
    }
  };

  if (!question) return <p>Loading...</p>;

  return (
    <div className="page-center">
      <div className="card">
        <h3>{question.title}</h3>

        <p><b>Question:</b> {question.description}</p>

        <p>
          <b>Answer:</b>{" "}
          {question.answer ? question.answer : "No answer yet"}
        </p>

        <p>
          <b>Answered By:</b>{" "}
          {question.answeredBy ? question.answeredBy : "N/A"}
        </p>

        {/* ✅ SHOW FOR SENIOR */}
        {user && user.role === "Senior" && (
          <>
            <textarea
              placeholder="Write your answer..."
              value={answer}
              onChange={(e) => setAnswer(e.target.value)}
            />

            <button className="btn" onClick={handleAnswer}>
              Submit Answer
            </button>
          </>
        )}

        <button className="btn" onClick={() => navigate("/dashboard")}>
          Back
        </button>
      </div>
    </div>
  );
}

export default ViewAnswers;
